external_knowledge:
- "masterpieces" refers to albums with high average ratings;
- "renowned artist" is the artist with ID '1', which could be any specific artist depending on the context, such as "The Beatles" or "Taylor Swift";
- "praised by multiple critics" means having more than one rating.

sql:
SELECT AVG(rating) AS average_rating
FROM ratings
WHERE album_id = 1;

SELECT album_title
FROM albums
ORDER BY album_title ASC;
